// OnConflict allows configuring the `ON CONFLICT` / `ON DUPLICATE KEY` clause
// of the `INSERT` statement. For example:
//
//	client.Inference.CreateBulk(builders...).
//		OnConflict(
//			// Update the row with the new values
//			// the was proposed for insertion.
//			sql.ResolveWithNewValues(),
//		).
//		// Override some of the fields with custom
//		// update values.
//		Update(func(u *ent.InferenceUpsert) {
//			SetCreatedAt(v+v).
//		}).
//		Exec(ctx)
func (_c *InferenceCreateBulk) OnConflict(opts ...sql.ConflictOption) *InferenceUpsertBulk {
	_c.conflict = opts
	return &InferenceUpsertBulk{
		create: _c,
	}
}

// OnConflictColumns calls `OnConflict` and configures the columns
// as conflict target. Using this option is equivalent to using:
//
//	client.Inference.Create().
//		OnConflict(sql.ConflictColumns(columns...)).
//		Exec(ctx)
func (_c *InferenceCreateBulk) OnConflictColumns(columns ...string) *InferenceUpsertBulk {
	_c.conflict = append(_c.conflict, sql.ConflictColumns(columns...))
	return &InferenceUpsertBulk{
		create: _c,
	}
}

// InferenceUpsertBulk is the builder for "upsert"-ing
// a bulk of Inference nodes.
type InferenceUpsertBulk struct {
	create *InferenceCreateBulk
}

// UpdateNewValues updates the mutable fields using the new values that
// were set on create. Using this option is equivalent to using:
//
//	client.Inference.Create().
//		OnConflict(
//			sql.ResolveWithNewValues(),
//			sql.ResolveWith(func(u *sql.UpdateSet) {
//				u.SetIgnore(inference.FieldID)
//			}),
//		).
//		Exec(ctx)
func (u *InferenceUpsertBulk) UpdateNewValues() *InferenceUpsertBulk {
	u.create.conflict = append(u.create.conflict, sql.ResolveWithNewValues())
	u.create.conflict = append(u.create.conflict, sql.ResolveWith(func(s *sql.UpdateSet) {
		for _, b := range u.create.builders {
			if _, exists := b.mutation.ID(); exists {
				s.SetIgnore(inference.FieldID)
			}
			if _, exists := b.mutation.CreatedAt(); exists {
				s.SetIgnore(inference.FieldCreatedAt)
			}
			if _, exists := b.mutation.Name(); exists {
				s.SetIgnore(inference.FieldName)
			}
			if _, exists := b.mutation.TenantName(); exists {
				s.SetIgnore(inference.FieldTenantName)
			}
			if _, exists := b.mutation.DeploymentName(); exists {
				s.SetIgnore(inference.FieldDeploymentName)
			}
			if _, exists := b.mutation.ServiceName(); exists {
				s.SetIgnore(inference.FieldServiceName)
			}
		}
	}))
	return u
}

// Ignore sets each column to itself in case of conflict.
// Using this option is equivalent to using:
//
//	client.Inference.Create().
//		OnConflict(sql.ResolveWithIgnore()).
//		Exec(ctx)
func (u *InferenceUpsertBulk) Ignore() *InferenceUpsertBulk {
	u.create.conflict = append(u.create.conflict, sql.ResolveWithIgnore())
	return u
}

// DoNothing configures the conflict_action to `DO NOTHING`.
// Supported only by SQLite and PostgreSQL.
func (u *InferenceUpsertBulk) DoNothing() *InferenceUpsertBulk {
	u.create.conflict = append(u.create.conflict, sql.DoNothing())
	return u
}

// Update allows overriding fields `UPDATE` values. See the InferenceCreateBulk.OnConflict
// documentation for more info.
func (u *InferenceUpsertBulk) Update(set func(*InferenceUpsert)) *InferenceUpsertBulk {
	u.create.conflict = append(u.create.conflict, sql.ResolveWith(func(update *sql.UpdateSet) {
		set(&InferenceUpsert{UpdateSet: update})
	}))
	return u
}

